  payload = '{"species": "Soursop", "species_slug": "soursop", "varieties": [{"name": "Seedling Selections (Queensland-Adapted)", "slug": "seedling-selections-queensland-adapted", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Queensland, Australia (grown from diverse tropical seed sources)", "traits": "Heart-shaped fruits, dark green skin with soft fleshy spines, fruit size 10-30cm long, weight 1.5-4kg", "flesh_fruit": "White, juicy, slightly fibrous, creamy texture with sweet-tart flavor combining strawberry, pineapple and citrus notes", "yield_notes": "12-24 fruits per tree annually, fruit production begins 2-3 years from seed in tropical conditions, 3-5 years in subtropics", "growing_notes": "Requires frost-free site with protection from cold winds. In Queensland, well-watered trees reach 4.5-5.5m in 6-7 years. Fruiting season begins April. Sensitive to temperatures below 5°C when young, requiring protection until established. Main pest is mealybug on fruits. Prefers deep, well-drained, semi-dry soil.", "availability": "Daley''s Fruit Tree Nursery, Fruitopia Nursery humid subtropical climates, Ross Creek Tropicals Gympie, Sunshine Coast nurseries"}, {"name": "Grafted Kyogle Selection", "slug": "grafted-kyogle-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Kyogle, New South Wales, Australia (subtropical selection)", "traits": "Medium-large fruit, heart-shaped, green skin, proven performer in marginal subtropical climate", "flesh_fruit": "White, juicy with sweet lemony taste (not sour like lemon), firm texture, less fibrous than seedlings", "yield_notes": "Good crop production, multiple fruits per season, bears within 2-3 years of grafting", "growing_notes": "", "availability": ""}, {"name": "Golden/Yellow Soursop Selection", "slug": "golden-yellow-soursop-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Rare selection available in Australian subtropical nurseries", "traits": "Large fruit, golden-yellow when ripe (distinguishing feature), spiny green skin that yellows at maturity", "flesh_fruit": "Sweet and aromatic, perfect blend of tropical fruits with berry hint, less acidic than standard green varieties", "yield_notes": "Good producer with proper care, typical soursop yield range", "growing_notes": "", "availability": ""}, {"name": "Smooth Flesh Selection", "slug": "smooth-flesh-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Queensland selection grown from smooth-fleshed variety", "traits": "Heart-shaped fruit, typical rough green skin with soft spines", "flesh_fruit": "Notable for smoother, less fibrous flesh texture, juicy and slightly acid, creamy consistency", "yield_notes": "Standard soursop productivity", "growing_notes": "Seedling selection specifically chosen for superior flesh texture. Excellent for fresh consumption and processing. Superb when pureed with vanilla ice cream. Requires subtropical to tropical climate with frost protection.", "availability": "Daley''s Fruit Tree Nursery"}, {"name": "Giant South American Selection", "slug": "giant-south-american-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "South American seed-grown selection", "traits": "Large conical fruits, typically 7kg+, specimens exceeding 10kg possible on established trees", "flesh_fruit": "Firm, white, less fibrous than other commercially available varieties", "yield_notes": "Large individual fruit size compensates for typical soursop shy-bearing habit", "growing_notes": "", "availability": ""}, {"name": "Sunshine Coast Grafted Selection", "slug": "sunshine-coast-grafted-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Sunshine Coast, Queensland selection", "traits": "Heart