otes": "", "availability": ""}, {"name": "Sweet Type (Sirsak Ratu - Indonesian influence)", "slug": "sweet-type-sirsak-ratu-indonesian-influence", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Southeast Asian selection, cultivated in tropical monsoon climates through historical trade connections", "traits": "Small to medium fruit, few-seeded, typically 1-2kg", "flesh_fruit": "Sub-acid flavor (lower acidity), sweeter than common types, preferred for fresh eating", "yield_notes": "Moderate productivity, fewer but sweeter fruits", "growing_notes": "Similar to sweet types grown in Indonesia and Philippines. Predominant in a few tropical monsoon climates localities. Best for fresh consumption. Excellent adaptation to tropical monsoon conditions with high humidity during fruit set. Thrives in Tropical monsoon warm temperatures (21-32°C).", "availability": "Specialty tropical monsoon climates nurseries, inquire at local fruit tree sellers"}, {"name": "Aguinaldo Type (Philippine Introduction)", "slug": "aguinaldo-type-philippine-introduction", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "Philippines, introduced to India through tropical fruit exchange programs", "traits": "Medium fruit approximately 1kg, yellow-green peel", "flesh_fruit": "Juicy, sub-acid (moderately acidic), 78% of fruit weight is edible, approximately 70 seeds per fruit", "yield_notes": "Good edible portion ratio, reliable cropper in tropical conditions", "growing_notes": "Part of Philippines'' major soursop production heritage (Western Visayas, Central Luzon leading regions). Adapted to similar tropical monsoon climate as tropical monsoon climates. Sub-acid types excellent for both fresh consumption and processing. Can be consumed fresh or used for juices and desserts.", "availability": "May be available through specialty importers or agricultural research stations in tropical monsoon climates"}, {"