esh_fruit": "White, mildly sweet like cucumber, crunchy texture", "yield_notes": "Large fruits, moderate yields on vines", "growing_notes": "Perfect for Tropical monsoon tropical climate. Warm-season crop loving heat. Highly valued in Ayurvedic medicine for cooling properties. Combats acidity, ulcers, keeps gut healthy. Used in curries, pickles, candies. Excellent storage (months). Grown throughout South India.", "availability": "Common throughout tropical monsoon climates markets and agricultural suppliers"}, {"name": "Snake Gourd (Chichinda, Padwal) 🏆", "slug": "snake-gourd-chichinda-padwal", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 3, "origin": "Native to South India, traditional in tropical monsoon climates cuisine", "traits": "Very long (up to 150cm), slender, twisted like snake; light green with white stripes", "flesh_fruit": "Mild, slightly sweet, soft texture when cooked", "yield_notes": "Prolific in hot humid conditions", "growing_notes": "Thrives in Tropical monsoon hot and humid tropical climate. Requires trellis support. Popular in tropical monsoon climates sambar and stir-fries. Fringed white flowers open at night. Harvest immature fruits before fibrous. Strengthens respiratory system, aids weight loss. Available during monsoon season.", "availability": "Common in tropical monsoon climates - local markets and agricultural stores"}, {"name": "Bitter Gourd (Karela, Pavakka) 🏆", "slug": "bitter-gourd-karela-pavakka", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 4, "origin": "Native to tropical monsoon climates and tropical regions of India", "traits": "Bumpy, spiky exterior; oblong shape; dark to light green", "flesh_fruit": "Distinctly bitter taste, crisp texture", "yield_notes": "Abundant on 10-15 ft vines", "growing_notes": "Staple in tropical monsoon climates kitchen gardens. Thrives in tropical climate. Excellent for managing blood sugar levels. Rich in iron, beta-carotene, vitamins. Valued in Ayurveda for blood purification. Anti-inflammatory properties. Grows throughout summer season in tropical monsoon climates.", "availability": "Universally available - every tropical monsoon climates market and nursery"}, {"name": "Apple Gourd / Tinda (Indian Squash) 🌱", "slug": "apple-gourd-tinda-indian-squash", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "Native to India, popular in South Asia", "traits": "Small, round or oval; green color; slight thorny surface; apple-sized", "flesh_fruit": "Mild flavor, takes on spice flavors", "yield_notes": "Good yields on compact vines", "growing_notes": "Well-adapted to tropical monsoon climate. Loves humid and hot conditions. Vines grow 1-2 meters. Can be grown in containers with vertical support. Matures 60-70 days. Popular summer vegetable in tropical monsoon climates.", "availability": "Available in tropical monsoon climates markets during summer season"}, {"name": "Yellow Crookneck Squash", "slug": "yellow-crookneck-squash", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 6, "origin": "Colonial America", "traits": "Yellow, curved neck, warted when mature", "flesh_fruit": "Pale yellow, buttery flavor", "yield_notes": "Productive in warm climates", "growing_notes": "Can adapt to Tropical monsoon tropical climate with good drainage. Needs protection from heavy monsoon rains. Best planted after main monsoon period. Heat tolerant. Harvest when 6 inches. Matures 50-60 days.", "availability": "Specialty seed suppliers in India, international seed companies"}, {"name": "Black Beauty Zucchini", "slug": "black-beauty-zucchini", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "sort_order": 7, "origin": "United States", "traits": "Dark green, cylindrical, 6-8 inches", "flesh_fruit": "White, tender, mild", "yield_notes": "Highly productive", "growing_notes": "Can be grown in tropical monsoon climates with proper management. Needs well-drained soil to prevent fungal issues in high humidity. Best grown in drier months (December-March). Requires regular harvest. Popular for international cooking. Matures 50-55 days.", "availability": "Select garden centers in tropical monsoon climates, online seed suppliers"}, {"name": "Heirloom varieties highlighted:", "slug": "heirloom-varieties-highlighted", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 8, "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}], "variety_count": 23}'::jsonb,
